/** @type {import('next').NextConfig} */
const nextConfig = {
  images: {
    unoptimized: true,
  },
};

module.exports = nextConfig;

import type { Config } from "tailwindcss";

const config: Config = {
  content: [
    "./src/app/**/*.{js,ts,jsx,tsx,mdx}",
    "./src/components/**/*.{js,ts,jsx,tsx,mdx}",
  ],
  theme: {
    extend: {
      colors: {
        paper: "#F2F0EB",
        "paper-dark": "#E8E4DD",
        ink: "#171412",
        "ink-light": "#3E3A38",
        dusk: "#4A5D7A",
        "dusk-light": "#6B7F9E",
      },
      fontFamily: {
        display: ["var(--font-fraunces)", "serif"],
        serif: ["var(--font-source-serif)", "serif"],
        sans: ["var(--font-ibm-plex)", "sans-serif"],
      },
    },
  },
  plugins: [],
};

export default config;

module.exports = {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
};

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  html {
    scroll-behavior: smooth;
  }
  body {
    font-feature-settings: "liga" 1, "kern" 1;
    @apply bg-paper text-ink antialiased;
  }
  ::selection {
    background-color: rgba(74, 93, 122, 0.15);
    color: #171412;
  }
}

@layer utilities {
  .hairline {
    @apply h-px bg-ink/10;
  }
}

export function cn(...classes: Array<string | false | undefined>) {
  return classes.filter(Boolean).join(" ");
}

export const siteMeta = {
  instagram: "@_tarankhan",
  email: "taran@tarankhan.com",
};

export const about = {
  headline:
    "Taran Khan is an award-winning writer and journalist. She publishes in the London Review of Books, Granta, the Guardian, Himal Southasian and Al Jazeera, among others. Her first book, Shadow City: A Woman Walks Kabul, won the Stanford Dolman Travel Book of the Year and the Tata Literature Live! First Book Award. She teaches nonfiction writing at Arvon and Faber Academy, and is a mentor for South Asia Speaks, a fellowship supporting emerging writers from the region. She also works with refugees, asylum seekers and Afghan women in supporting their writing, including as a tutor with Untold Narratives and Fences & Frontiers. Taran was the Royal Literary Fund Fellow at Goldsmiths, University of London from 2024 to 2026, and has received fellowships from MacDowell, Pro Helvetia (Swiss Arts Council), the Jan Michalski Foundation for Writing and Literature, and the Hugo Burge Foundation.",
  origin: "She grew up in Aligarh, in north India, and now lives in London.",
};

export const book = {
  title: "Shadow City: A Woman Walks Kabul",
  publisher: "Penguin Random House, 2019",
  awards: [
    "Winner — Stanford Dolman Travel Book of the Year",
    "Winner — Tata Literature Live! First Book Award",
  ],
  translations: "Translated into Arabic and Chinese.",
  quote:
    "One of the first things I was told when I arrived in Kabul was never to walk.",
  body: [
    "When Taran Khan first arrived in Kabul in 2006, she found a city both familiar and unknown. Falling in with poets, archaeologists, and filmmakers, and guided by her grandfather's voice – who had never been to Kabul, but knew it intimately through books and poetry – she explored it across several returns.",
    "Shadow City is the record of those walks: a personal and meditative portrait of a city the world knows mostly through war. Moving between graveyards and libraries, cinemas and gardens, Khan maps the layered histories of a place in flux, and the lives of the people remaking a city with a 3,000 year old history, and is forever in flux.",
  ],
  extractUrl: "#",
  praise: [
    { text: "A fabulous piece of writing… I recommend it unreservedly.", source: "William Dalrymple" },
    { text: "A brilliant book.", source: "Christina Lamb, author of Farewell Kabul" },
    { text: "Offers a unique on-the-ground view of the city… a refreshing counterpoint to the macho foreign-correspondent genre…", source: "Amelia Gentleman, the Guardian", long: true },
    { text: "Khan illuminates Kabul's life-affirming humanity.", source: "Times Literary Supplement" },
    { text: "By excavating Afghanistan's forgotten past, Khan rescues its future, too. Her lyrical prose brings to life the most daring truth a writer can offer: that these tragedies were not preordained, and another Afghanistan is possible.", source: "Anand Gopal, author of No Good Men Among the Living", long: true },
    { text: "Taran Khan's achievement is to have caught it in an affecting and beautifully observed portrait, a word-map that will endure.", source: "Tim Mackintosh-Smith" },
    { text: "An intricate, intimate portrait of a heartbreaking city, its people and its past, written with nuance, love and attention.", source: "Alice Albinia, author of Empires of the Indus" },
    { text: "Taran Khan invites and leads us into a wonderful journey through the streets of Kabul, its history and culture. Step by step with her, we breathe in the city's air of mysticism and mystery.", source: "Atiq Rahimi, author of The Patience Stone", long: true },
    { text: "Powerfully evocative.", source: "Kapka Kassabova" },
    { text: "Shadow City moved me to tears… no book has done a more honest and heart-warming job in recent years… Thrilling.", source: "Supriya Nair, Mumbai Mirror", long: true },
  ],
  buyLinks: [
    { label: "Bookshop.org", url: "#" },
    { label: "Hive", url: "#" },
    { label: "Stanfords", url: "#" },
    { label: "Amazon India", url: "#" },
    { label: "Amazon UK", url: "#" },
  ],
  reviewLinks: [
    { label: "the Guardian", url: "#" },
    { label: "Times Literary Supplement", url: "#" },
    { label: "Mumbai Mirror", url: "#" },
    { label: "Outlook Traveller", url: "#" },
    { label: "Chicago Review of Books", url: "#" },
  ],
  press: [
    { label: "Platform — Platform Travels via Books", url: "#" },
    { label: "Five Books — Shadow City recommended", url: "#" },
    { label: "Scroll — The longer I spent in Kabul…", url: "#" },
  ],
  contributions: [
    { title: "How I Write: Writers on Their Craft", meta: "Edited by Sonia Faleiro (HarperCollins India, 2024)", note: "A landmark collection of conversations on craft from writers connected to South Asia, created by the South Asia Speaks fellowship." },
    { title: "Day's End Stories: Life After Sundown in Small-Town India", meta: "Edited by Subuhi Jiwani (Tranquebar Press, 2014)", note: "Contributor of the essay Little Women, Fewer Men, on nightfall, freedom, and growing up in Aligarh." },
  ],
};

export const reportage = {
  intro: [
    "I report and write essays on culture, conflict, migration, and travel.",
    "I'm drawn to the fringes of places and the invisible layers beneath events. I explore the long shadow of violence and rupture, and also of love and endurance, by focusing on the lives of ordinary people, embedding in their narratives to reach the bigger story.",
    "Cities and walking recur in my work, as do exiles and migrants, and the liminal spaces of memory and our imagination.",
  ],
  pieces: [
    { title: "Making It in Bollywood", pub: "The Dial", year: "2026", url: "#", excerpt: "Inside the world of Mumbai's 'strugglers' — the aspiring actors who arrive in the city by the thousand — and what their journeys reveal about who gets to be a star in modern India." },
    { title: "The Bookseller of Southall", pub: "London Review of Books", year: "2025", url: "#", excerpt: "Meeting Shah Muhammad Rais, once Kabul's most famous bookseller, now selling Afghan books as a refugee in London." },
    { title: "'I want my expedition to speak for Afghan women'", pub: "Hyphen", year: "2025", url: "#", excerpt: "Walking the Peak District with Freshta Ibrahimi, who hopes to be the first Afghan woman to summit Everest." },
    { title: "Shadow City, Invisible City: Walking Through an Ever-Changing Kabul", pub: "Literary Hub", year: "2021", url: "#", excerpt: "An essay written after the Taliban's takeover of Kabul on the changing nature of the city and the lives of its residents." },
    { title: "The Buddha of Kabul", pub: "Guernica", year: "2024", url: "#", excerpt: "What the excavation of a Buddhist monastery on the fringes of Kabul reveals about the layers of history beneath the city's surface." },
    { title: "The Dam", pub: "Granta", year: "2021", url: "#", excerpt: "Walking the length of Steindamm in Hamburg reveals a city of Afghan refugees and asylum seekers." },
    { title: "Mumbai: a Virtual Tour Through Books, Film, Music and Food", pub: "the Guardian", year: "2021", url: "#", excerpt: "A portrait of the city through its culture, for readers travelling in their imagination." },
    { title: "The Making of a Refugee", pub: "Himal Southasian", year: "2019", url: "#", excerpt: "A long-form series reported from Hamburg, on the lives and work of Afghan artists, filmmakers and musicians in exile." },
    { title: "How Ranveer Singh Made It", pub: "The Caravan", year: "2016", url: "#", excerpt: "A profile of the Bollywood star, and how stardom is manufactured and maintained in Indian pop culture." },
  ],
};

export const workshops = {
  philosophy: "I teach creative nonfiction, narrative journalism, and life writing. I am a tutor with Arvon Foundation and lead a walking and writing workshop for Faber Academy. Read about my approach in this essay for Faber. I am a mentor with South Asia Speaks, where I work with writers from across the region for a year as they build book-length nonfiction. My editorial work with Untold Narratives, Fences&Frontiers and other groups supports writing by asylum seekers, refugees and at-risk Afghan women. In 2025 I guest-edited a special issue of Shuddhashar on Afghan exile, commissioning and editing writers from the country and across the diaspora. I was the Royal Literary Fund Fellow at Goldsmiths, University of London, where I provided writing inputs to students from across disciplines and academic degrees.",
  recent: [
    { title: "Creative nonfiction", venue: "Faber Academy, London", year: "2026" },
    { title: "Creative nonfiction", venue: "Arvon Foundation", year: "" },
  ],
  consultation:
    "One-to-one consultations for writers working on nonfiction – from memoir, narrative journalism, travel, and essay — focused on structure, voice, and shaping your material for submission.",
};

export const events = {
  intro:
    "I have been invited to speak at festivals, universities, and cultural institutions on Afghanistan, exile, walking, and writing about place.",
  talks: [
    { title: "The Travel Session", venue: "Jaipur Literature Festival", year: "2022", type: "watch", url: "#" },
    { title: "98: Glimpses of Kabul", venue: "Bangalore International Centre", year: "", type: "watch", url: "#", note: "In conversation with Samhita Arni" },
    { title: "Should We Have Stayed at Home?", venue: "5×15 Stories", year: "", type: "event", url: "#" },
    { title: "Shadow City: A Woman Walks Kabul", venue: "Kendal Mountain Festival", year: "2023", type: "watch", url: "#" },
  ],
  podcasts: [
    { title: "Gone to Timbuktu", host: "Sophy Roberts", url: "#", note: "On walking Kabul, memory, and writing conflict." },
    { title: "The Adventure Podcast", host: "Matt Croft", url: "#", note: "On my family connection to Afghanistan and what it means to walk in Kabul." },
  ],
};

export const contact = {
  agent: {
    name: "Emma Paterson",
    company: "Aitken Alexander Associates",
    email: "emma@aitkenalexander.co.uk",
  },
  newsletter: {
    action: "https://formspree.io/f/YOUR_FORM_ID",
    text: "For occasional news and updates, sign up for my newsletter.",
  },
};

"use client";

import Link from "next/link";
import { useState } from "react";

const links = [
  { href: "/", label: "About" },
  { href: "/book", label: "Book" },
  { href: "/reportage", label: "Reportage" },
  { href: "/workshops", label: "Workshops" },
  { href: "/events", label: "Events" },
  { href: "/contact", label: "Contact" },
];

export default function Navigation() {
  const [open, setOpen] = useState(false);

  return (
    <header className="sticky top-0 z-50 bg-paper/90 backdrop-blur-sm border-b border-ink/5">
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-20 py-6 flex justify-between items-baseline">
        <Link
          href="/"
          className="font-display text-xl md:text-2xl tracking-tight text-ink hover:text-dusk transition-colors"
        >
          Taran Khan
        </Link>

        <nav className="hidden md:flex gap-8 font-sans text-xs uppercase tracking-widest text-ink-light">
          {links.map((l) => (
            <Link
              key={l.href}
              href={l.href}
              className="relative group hover:text-dusk transition-colors"
            >
              {l.label}
              <span className="absolute -bottom-1 left-0 w-0 h-px bg-dusk transition-all group-hover:w-full" />
            </Link>
          ))}
        </nav>

        <button
          onClick={() => setOpen(true)}
          className="md:hidden font-sans text-xs uppercase tracking-widest text-ink-light"
        >
          Menu
        </button>
      </div>

      {open && (
        <div className="md:hidden fixed inset-0 bg-paper z-40 flex flex-col items-center justify-center gap-8">
          <button
            onClick={() => setOpen(false)}
            className="absolute top-6 right-6 font-sans text-xs uppercase tracking-widest text-ink-light"
          >
            Close
          </button>
          {links.map((l) => (
            <Link
              key={l.href}
              href={l.href}
              onClick={() => setOpen(false)}
              className="font-display text-3xl text-ink hover:text-dusk transition-colors"
            >
              {l.label}
            </Link>
          ))}
        </div>
      )}
    </header>
  );
}

import Link from "next/link";
import { siteMeta } from "@/data/content";

export default function Footer() {
  return (
    <footer className="w-full px-6 md:px-12 lg:px-20 py-12 border-t border-ink/10 mt-auto">
      <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <span className="font-display text-lg text-ink">Taran Khan</span>
          <span className="block text-sm text-ink-light font-sans">Writer & Journalist</span>
        </div>

        <Link
          href="https://instagram.com/_tarankhan"
          target="_blank"
          rel="noopener noreferrer"
          className="font-sans text-sm uppercase tracking-wider text-ink-light hover:text-dusk transition-colors"
        >
          Instagram {siteMeta.instagram}
        </Link>

        <span className="font-sans text-xs text-ink-light/50">
          &copy; {new Date().getFullYear()} Taran Khan. All rights reserved.
        </span>
      </div>
    </footer>
  );
}

import type { Metadata } from "next";
import { Fraunces, Source_Serif_4, IBM_Plex_Sans } from "next/font/google";
import "./globals.css";
import Navigation from "@/components/Navigation";
import Footer from "@/components/Footer";

const fraunces = Fraunces({
  subsets: ["latin"],
  variable: "--font-fraunces",
  display: "swap",
  weight: ["400", "500", "600"],
});

const sourceSerif = Source_Serif_4({
  subsets: ["latin"],
  variable: "--font-source-serif",
  display: "swap",
  weight: ["400", "500", "600"],
});

const ibmPlex = IBM_Plex_Sans({
  subsets: ["latin"],
  variable: "--font-ibm-plex",
  display: "swap",
  weight: ["400", "500"],
});

export const metadata: Metadata = {
  title: {
    default: "Taran Khan | Writer & Journalist",
    template: "%s — Taran Khan",
  },
  description:
    "Taran Khan is an award-winning writer and journalist, author of Shadow City: A Woman Walks Kabul.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body
        className={`${fraunces.variable} ${sourceSerif.variable} ${ibmPlex.variable} font-serif min-h-screen flex flex-col`}
      >
        <Navigation />
        <main className="flex-1">{children}</main>
        <Footer />
      </body>
    </html>
  );
}

import type { Metadata } from "next";
import { reportage } from "@/data/content";

export const metadata: Metadata = {
  title: "Reportage & Essays",
  description:
    "Long-form journalism and essays by Taran Khan on Afghanistan, migration, gender, and the life of cities.",
};

export default function ReportagePage() {
  return (
    <div className="px-6 md:px-12 lg:px-20 py-16 max-w-7xl mx-auto">
      <h1 className="font-display text-5xl md:text-6xl lg:text-7xl text-ink mb-12">
        Reportage
        <br />
        <span className="italic text-ink-light/60">&amp; Essays</span>
      </h1>
      <div className="max-w-3xl mb-20 space-y-6">
        {reportage.intro.map((p, i) => (
          <p
            key={i}
            className="font-serif text-lg md:text-xl leading-relaxed text-ink-light"
          >
            {p}
          </p>
        ))}
      </div>
      <div className="border-t border-ink/10">
        {reportage.pieces.map((piece, i) => (
          <a
            key={i}
            href={piece.url}
            className="group block border-b border-ink/10 py-8 md:py-10 hover:bg-white/40 transition-colors"
          >
            <div className="grid grid-cols-1 md:grid-cols-12 gap-4 md:gap-8 items-baseline">
              <div className="md:col-span-3">
                <span className="font-sans text-xs uppercase tracking-widest text-ink-light/50">
                  {piece.pub}
                </span>
                <span className="block md:hidden font-sans text-xs text-ink-light/30 mt-1">
                  {piece.year}
                </span>
              </div>

              <div className="md:col-span-7">
                <h3 className="font-serif text-xl md:text-2xl lg:text-3xl group-hover:text-dusk transition-colors leading-snug mb-2 text-ink">
                  {piece.title}
                </h3>
                <p className="font-serif text-sm md:text-base text-ink-light leading-relaxed max-w-xl opacity-0 max-h-0 group-hover:opacity-100 group-hover:max-h-40 transition-all duration-500 overflow-hidden">
                  {piece.excerpt}
                </p>
              </div>

              <div className="md:col-span-2 md:text-right hidden md:block">
                <span className="font-sans text-xs uppercase tracking-widest text-ink-light/30">
                  {piece.year}
                </span>
              </div>
            </div>
          </a>
        ))}
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import { events } from "@/data/content";

export const metadata: Metadata = {
  title: "Events — Talks, Appearances & Podcasts",
  description:
    "Taran Khan speaks at festivals and on podcasts about Afghanistan, exile, walking, and the writing of place.",
};

export default function EventsPage() {
  return (
    <div className="px-6 md:px-12 lg:px-20 py-16 max-w-7xl mx-auto">
      <h1 className="font-display text-5xl md:text-6xl lg:text-7xl text-ink mb-12">
        Events
      </h1>
      <p className="max-w-3xl font-serif text-lg text-ink-light mb-16 leading-relaxed">
        {events.intro}
      </p>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
        <section>
          <h2 className="font-display text-3xl text-ink mb-8 pb-4 border-b border-ink/10">
            Talks &amp; Appearances
          </h2>
          <div className="space-y-8">
            {events.talks.map((talk, i) => (
              <div key={i} className="group">
                <div className="flex justify-between items-baseline mb-1">
                  <h3 className="font-serif text-xl md:text-2xl group-hover:text-dusk transition-colors text-ink">
                    {talk.title}
                  </h3>
                  {talk.year && (
                    <span className="font-sans text-xs uppercase tracking-widest text-ink-light/50">
                      {talk.year}
                    </span>
                  )}
                </div>
                <p className="font-serif text-sm text-ink-light mb-2">
                  {talk.venue}
                  {talk.note ? ` — ${talk.note}` : ""}
                </p>
                <a
                  href={talk.url}
                  className="font-sans text-sm uppercase tracking-wider text-dusk hover:text-ink transition-colors"
                >
                  {talk.type === "watch" ? "Watch \u2192" : "Event \u2192"}
                </a>
              </div>
            ))}
          </div>
        </section>

        <section>
          <h2 className="font-display text-3xl text-ink mb-8 pb-4 border-b border-ink/10">
            Podcasts
          </h2>
          <div className="space-y-8">
            {events.podcasts.map((pod, i) => (
              <div key={i} className="group">
                <h3 className="font-serif text-xl md:text-2xl group-hover:text-dusk transition-colors mb-1 text-ink">
                  {pod.title}
                </h3>
                <p className="font-serif text-sm text-ink-light mb-1">
                  with {pod.host}
                </p>
                <p className="font-serif text-sm text-ink-light/70 mb-3">
                  {pod.note}
                </p>
                <a
                  href={pod.url}
                  className="font-sans text-sm uppercase tracking-wider text-dusk hover:text-ink transition-colors"
                >
                  Listen &rarr;
                </a>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
}
